import{_ as t,f as o,o as r,aM as a}from"./chunks/framework.c_X9LrYI.js";const e="/docs/assets/55b735603f328da23d1d85b6b07b425.Hqp2ApwB.jpg",m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"column/Travel/index.md","filePath":"column/Travel/index.md","lastUpdated":1708678838000}'),s={name:"column/Travel/index.md"},l=a('<h2 id="🤯-大型记录之沪上漂泊记" tabindex="-1">🤯 大型记录之沪上漂泊记 <a class="header-anchor" href="#🤯-大型记录之沪上漂泊记" aria-label="Permalink to &quot;🤯 大型记录之沪上漂泊记&quot;">​</a></h2><h1 style="color:var(--vp-c-brand-1);">开篇 !!! </h1><p>我是一名带专前端应届生，大学时接触过一些前端知识，对其产生了兴趣，于是自学前端并考虑将其作为后续的工作方向。我不太喜欢运动，以前接触过一些武术。游戏方面，我玩过原神、王者、蛋仔等休闲手游。 <img src="'+e+'" alt="Alt text"></p><h3 id="求职经历" tabindex="-1">求职经历 <a class="header-anchor" href="#求职经历" aria-label="Permalink to &quot;求职经历&quot;">​</a></h3><ul><li><strong>2022 年 2 月</strong>：疫情爆发前投出第一波简历，面试了两家公司，拿到自研公司的 offer，但不久后因疫情公司业务停止而被辞退。</li><li><strong>2022 年 3 月</strong>：重新找工作，面试机会少，遇到了奇葩公司。</li><li><strong>2022 年 4 月</strong>：被“三个人的小公司”PUA，不仅白干还被拉黑。</li><li><strong>2022 年 5 月</strong>：拿下一家与上海公立医院对接的公司 offer 并入职。</li></ul><h3 id="经验总结" tabindex="-1">经验总结 <a class="header-anchor" href="#经验总结" aria-label="Permalink to &quot;经验总结&quot;">​</a></h3><ol><li><strong>法律意识</strong>：遇到类似公司要增强法律意识，采取录音、截图等方式留存证据。</li><li><strong>面试准备</strong>：提前了解公司情况，面试时问清楚所有问题。</li><li><strong>工作选择</strong>：不接受夜班，避免加入不正规的公司。</li></ol><h3 id="面试题总结" tabindex="-1">面试题总结 <a class="header-anchor" href="#面试题总结" aria-label="Permalink to &quot;面试题总结&quot;">​</a></h3><ol><li><strong>html</strong>：http 协议、web 攻击方式、DNS、http 和 https 的区别、状态码等。</li><li><strong>css</strong>：定位方式、垂直居中方法。</li><li><strong>js</strong>：对象合并、数组操作、基本数据类型和引用数据类型的区别、递归等。</li><li><strong>es6</strong>：es6 新特性、Promise、同源与不同源、跨域方式等。</li><li><strong>Vue</strong>：路由模式、同源、跨域、watch 和 computed 的区别、vuex 状态、mutations 的用法等。</li><li><strong>大数据可视化，echarts</strong>：常见属性、适配方法。</li><li><strong>小程序</strong>：第三方 ui 框架、生命周期、打包问题、上线流程等。</li><li><strong>后管（中台）系统</strong>：token 存放位置、动态路由用途、权限判断、前置导航守卫等。</li><li><strong>其他</strong>：ts、jQuery 事件委托、D3.js、three.js、Antdv 框架、uview、前端性能优化等。</li></ol><h3 id="未来计划" tabindex="-1">未来计划 <a class="header-anchor" href="#未来计划" aria-label="Permalink to &quot;未来计划&quot;">​</a></h3><p>我目前在上海某互联网公司从事前端开发工程师的工作，后续可能会因工资和技术问题更换工作。未来我会考虑升本，学习建模、鸿蒙、3D 游戏开发等技术。</p>',11),n=[l];function i(d,c,h,g,_,u){return r(),o("div",null,n)}const f=t(s,[["render",i]]);export{m as __pageData,f as default};
